SET NAMES utf8mb4;

ALTER TABLE products
ADD COLUMN age_rating VARCHAR(10) NOT NULL DEFAULT '16+' AFTER description;

UPDATE products SET age_rating = '12+', description = 'История шумного ниндзя Наруто Узумаки, который мечтает добиться признания деревни и стать Хокаге. Первый том знакомит с Командой 7, наставником Какаси и началом пути героя.' WHERE id = 1;
UPDATE products SET age_rating = '12+', description = 'Приключенческая манга о Монки Д. Луффи и его мечте найти легендарное сокровище One Piece. Сюжет задаёт тон большому морскому путешествию и формированию команды Соломенной Шляпы.' WHERE id = 2;
UPDATE products SET age_rating = '18+', description = 'Мрачное тёмное фэнтези о мечнике Гатсе, мире наёмников, предательства и жажды мести. История разворачивается в жестокой средневековой реальности с тяжёлыми взрослыми темами.' WHERE id = 3;
UPDATE products SET age_rating = '12+', description = 'Романтическая фантастика о Таки и Мицухе, которые внезапно начинают меняться телами, хотя никогда не встречались. Манга сочетает школьную повседневность, мистику и историю о связи через расстояние.' WHERE id = 4;
UPDATE products SET age_rating = '16+', description = 'Юдзи Итадори оказывается втянут в мир проклятий и магов после встречи с опасным артефактом. Первый том задаёт динамичный боевой сюжет, школу экзорцистов и угрозу Сукуны.' WHERE id = 5;
UPDATE products SET age_rating = '18+', description = 'Дэндзи мечтает о простой жизни, но вместо этого попадает в жестокую охоту на демонов и становится частью государственной организации. Манга известна резким экшеном, чёрным юмором и кровавыми сценами.' WHERE id = 7;
UPDATE products SET age_rating = '12+', description = 'История Идзуку Мидории, мальчика без суперсил, который всё равно мечтает стать героем. После судьбоносной встречи с Всемогущим начинается путь в академию героев и мир причуд.' WHERE id = 8;
UPDATE products SET age_rating = '16+', description = 'После трагедии в семье Тандзиро Камадо вступает в Корпус истребителей демонов, чтобы спасти сестру Нэдзуко. Первый том сочетает фэнтези, японскую атмосферу и напряжённые сражения.' WHERE id = 9;
UPDATE products SET age_rating = '18+', description = 'Кэн Канэки оказывается между миром людей и гулей после роковой встречи, изменившей его тело и жизнь. Сэйнэн-манга соединяет ужасы, психологию и тему потери собственной идентичности.' WHERE id = 10;
UPDATE products SET age_rating = '16+', description = 'Психологический триллер о нейрохирурге Кэндзо Тэмме, чья жизнь рушится после выбора между карьерой и спасением ребёнка. История ведёт к серии преступлений, моральным дилеммам и охоте на чудовище в человеческом облике.' WHERE id = 11;
UPDATE products SET age_rating = '12+', description = 'Школьная романтика о популярной Хори и тихом Миямуре, которые неожиданно узнают друг о друге больше, чем видят окружающие. Манга строится на повседневности, юморе и постепенном сближении героев.' WHERE id = 12;
UPDATE products SET age_rating = '12+', description = 'Драма о школьной травле, чувстве вины и попытке исправить прошлое. История Сёи и Сёко поднимает темы одиночества, взросления, общения и принятия себя и других.' WHERE id = 13;
UPDATE products SET age_rating = '16+', description = 'Субару Нацуки внезапно переносится в другой мир и обнаруживает, что после смерти возвращается к определённой точке во времени. Исекай сочетает фэнтези, детективную интригу и тяжёлые эмоциональные испытания.' WHERE id = 14;
UPDATE products SET age_rating = '16+', description = 'Сон Джин-У считался слабейшим охотником, пока не получил шанс развиваться по собственным правилам, словно в RPG. Манга предлагает мир подземелий, монстров, прокачки и сольного выживания.' WHERE id = 15;
UPDATE products SET age_rating = '18+', description = 'Культовый хоррор Дзюндзи Ито о городе, который постепенно сходит с ума из-за навязчивого образа спирали. Манга держится на тревожной атмосфере, телесном ужасе и пугающих визуальных сценах.' WHERE id = 16;
UPDATE products SET age_rating = '16+', description = 'Лайт Ягами находит тетрадь, способную убивать любого, чьё имя в неё вписано, и начинает собственную войну за идеальный мир. Сюжет строится на интеллектуальном противостоянии, детективе и моральном конфликте.' WHERE id = 17;
UPDATE products SET age_rating = '12+', description = 'Комедийная манга о самурае Гинтоки Сакате, который подрабатывает на любые странные поручения в Японии эпохи Эдо, покорённой инопланетянами. Внутри много пародий, абсурдного юмора и неожиданных боевых арок.' WHERE id = 18;
UPDATE products SET age_rating = '12+', description = 'Тонкая повседневная драма о молодом профессиональном игроке в сёги Рэе Кирияме, который учится заново выстраивать отношения с людьми. Манга соединяет спорт, внутренние переживания и тему взросления.' WHERE id = 19;
UPDATE products SET age_rating = '12+', description = 'Спортивная история о команде старшей школы Сэйрин и невидимом на площадке игроке Куроко, который мечтает вывести друзей к победе. Первый том знакомит с баскетбольной тактикой, соперничеством и командным ростом.' WHERE id = 20;
UPDATE products SET age_rating = '16+', description = 'Детективная научная фантастика, переосмысляющая арку Astro Boy как историю серии загадочных убийств людей и роботов. Главный герой, робот-следователь Гезихт, постепенно раскрывает масштабный заговор.' WHERE id = 21;
UPDATE products SET age_rating = '18+', description = 'Киберпанк-манга о спецподразделении Section 9, которое борется с терроризмом, киберпреступностью и угрозами цифровой эпохи. В центре сюжета — Мотоко Кусанаги, технологии будущего и вопросы о природе личности.' WHERE id = 22;
UPDATE products SET age_rating = '12+', description = 'После смерти обычный офисный работник Сатору Миками перерождается в другом мире в виде слизи и начинает собирать вокруг себя союзников. История сочетает исекай, юмор, фэнтези и развитие собственного государства монстров.' WHERE id = 23;
UPDATE products SET age_rating = '18+', description = 'Рико и роботизированный мальчик Рэг отправляются в Бездну — гигантскую пропасть с древними артефактами, чудовищами и смертельными уровнями глубины. За красивой оболочкой скрываются тревожная атмосфера и очень жёсткие сцены.' WHERE id = 24;
